import { z } from "zod";

export const validateRequestSchema = z.object({
  type: z.enum(["email", "phone", "url", "domain"]),
  value: z.string().min(1).max(500),
  deep: z.boolean().optional().default(false),
});

export const validateChecksSchema = z.object({
  format: z.boolean(),
  mx: z.boolean().optional(),
  smtp: z.boolean().optional(),
  disposable: z.boolean().optional(),
});

export const validateResponseSchema = z.object({
  valid: z.boolean(),
  type: z.string(),
  value: z.string(),
  checks: validateChecksSchema,
  suggestion: z.string().optional(),
});

export type ValidateRequest = z.infer<typeof validateRequestSchema>;
export type ValidateResponse = z.infer<typeof validateResponseSchema>;
export type ValidateChecks = z.infer<typeof validateChecksSchema>;
